            continue
        p = p
        if len(p) < 2:
            continue
        cats.append(p)
    # further split on / and |
    final = []
    for c in cats:
        temp = c.replace('/', ',').replace('|', ',')
        for sub in [t.strip() for t in temp.split(',') if t.strip()]:
            final.append(sub)
    seen = set()
    out = []
    for c in final:
        if c not in seen:
            seen.add(c)
            out.append(c)
    return out

